var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"전대장님의 포격이 제대로 들어갔군!","JPN":"戦隊長の砲撃がモロに入ったぜ！","ENG":"Nice shot, Commander!","TWN":"隊長的砲擊奏效了！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"크로노스 격파! 남은 건 오합지졸들뿐입니다!","JPN":"クロノス撃破！　残るは烏合の衆だけです！","ENG":"Chronos destroyed! The rest of them are too easy!","TWN":"擊破克羅諾斯了！現在只剩下一群烏合之眾了！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"말도 안 돼......!","JPN":"嘘でしょ……！","ENG":"No way!","TWN":"不可能……！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"기신급 육전병기를 뭉개 버리다니 저게 가능한 일이야......?!","JPN":"機神級陸戦兵器をペシャッと潰してしまうなんて、\\nそんなのありなの……！？","ENG":"How did she crush a god-class mech like that?","TWN":"機神級陸戰兵器竟然被擊毀了，這怎麼可能……？！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SHIELD_ADMIN_CORRUPT_MAZE","text":{"KOREA":"부, 부전대장님!","JPN":"ふ、副戦隊長殿！","ENG":"D-Deputy Commander!","TWN":"副隊長！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SHIELD_ADMIN_CORRUPT_MAZE","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SHIELD_ADMIN_CORRUPT_MAZE","text":{"KOREA":"전선이 무너지고 있습니다! 어떻게 할까요?","JPN":"戦線が崩れつつあります！　いかがいたしましょう？","ENG":"Our line of defense has been compromised! What should we do?","TWN":"戰線崩潰了！我們該怎麼辦？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SHIELD_ADMIN_CORRUPT_MAZE","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"저 녀석들이 침식체로 완전히 변할 때까지만 기다리면 된다고 했잖아!","JPN":"あいつらが完全な侵食体に変異するまで長引かせれば\\nいいって言ったじゃない！","ENG":"I told you we just had to wait until they turned into C.O.s!","TWN":"我不是叫你們撐到他們完全變成侵蝕體的時候嗎！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIELD_ADMIN_CORRUPT_MAZE","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"너희들은 겨우 그것도 못 버티는 거야?!","JPN":"あなたたちは時間稼ぎすらできないの！？","ENG":"You guys couldn't even last that long?","TWN":"你們連這都做不到嗎？！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIELD_ADMIN_CORRUPT_MAZE","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SHIELD_ADMIN_CORRUPT_MAZE","text":{"KOREA":"하, 하지만......","JPN":"で、ですが……","ENG":"B-but...","TWN":"但、但是……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIELD_ADMIN_CORRUPT_MAZE","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"크아악! 개자식, 날 총알받이로 써......?!","JPN":"グアァッ！　このクソ野郎、俺を弾避けにしてくれたな……！？","ENG":"Aaack! You bastard! Using me like a shield?","TWN":"啊啊啊！混蛋，竟敢把我當作擋箭牌……？！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"닥쳐! 움직이지도 못하면 얌전히 엄폐물이라도 되라고!","JPN":"黙れ！　動けないんだったら、大人しく遮蔽物にでも\\nなりやがれってんだ！","ENG":"Shut up! You might as well as provide some cover if you can't even move!","TWN":"閉嘴！反正你又動不了了，還不如乖乖當我的擋箭牌！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HOWLING_02"},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"힘이 부족해......! 힘이 부족하다고! 네놈이라도 먹어치운다면......!","JPN":"力が足りん……！　もっと力が要るんだ！\\n貴様を喰ってしまえば……！","ENG":"I don't have enough power... I need more power! Maybe if I devour you...","TWN":"力量不夠……！力量還不夠！我要是能吃掉你……！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HOWLING_03"},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"이건 말도 안 돼......!","JPN":"こんなのあり得ないわ……！","ENG":"You've got to be kidding me!","TWN":"不可能……！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"어째서 밀리는 거야?! 힘은 우리가 더 강할 텐데!","JPN":"なぜ押されているの！？　戦力は私たちが上回ってるはずよ！","ENG":"Why are we losing? We're a lot stronger than them!","TWN":"為什麼會這樣？！論力量的話，明明是我們更強啊！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"큭......?!","JPN":"くっ……！？","ENG":"Ugh!","TWN":"唔……？！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_BOOM"},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"아직도 모르겠어?","JPN":"まだわからないの？","ENG":"Don't you get it?","TWN":"妳還不明白嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"원본......!","JPN":"オリジナル……！","ENG":"My original!","TWN":"本體……！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"믿는 사람도, 목숨 맡길 사람도 없이 전쟁을 치르겠다고?","JPN":"信じる相手も、命を預ける相手もいないのに戦争をしようって？","ENG":"You want to fight a war when you don't trust anyone with your life?","TWN":"沒有能夠信賴、沒有能夠託付性命的戰友，這是要怎麼打仗呢？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그래서야 하나하나의 힘은 강할지 몰라도 어린애들 병정 놀이나 마찬가지야.","JPN":"そんなの個々の力は強いかもしれないけど、\\nお子様の兵隊ごっこと同じだわ。","ENG":"You may be strong individually, but as an army, you may as well as be toy soldiers.","TWN":"雖然你們每一個個體的力量都很強，但就只像是小孩子玩騎馬打仗一樣。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"흉내를 내려면 제대로 내야지. 안 그래?","JPN":"まねっこにしても杜撰すぎるのよ。わかるでしょう？","ENG":"I guess it didn't occur to you that you should also mimic our teamwork. Isn’t that right?","TWN":"要模仿就要模仿得徹底一點，對吧？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"닥쳐! 싸구려 복제품 주제에......!","JPN":"黙れ！　安物のコピー品の分際で……！","ENG":"Shut up! You're nothing but a cheap clone!","TWN":"閉嘴！區區卑劣的克隆人……！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"크윽......?!","JPN":"くうっ……！？","ENG":"Ngh!","TWN":"呃……？！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_QM","text":{"KOREA":"진실로 하찮기 짝이 없는 미물이로구나.","JPN":"誠に取るに足らぬ、塵芥にも劣る生き物よ。","ENG":"Oh, ye petty worms.","TWN":"果真是一隻沒用至極的廢物。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"다, 당신은......?","JPN":"あ、あなたは……？","ENG":"Y-you?","TWN":"你、你是……？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_QM","text":{"KOREA":"이제 곧 왕께서 걸음 하실 길을 닦는 것조차 이리 미흡하다니......","JPN":"やがて王が歩まれる道を整える役目さえ務まらぬか……","ENG":"Your only task was to pave the path for the Queen's return... yet you have failed at something so trivial...","TWN":"連王即將要踏上的道路都掃不乾淨嗎……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_QM","text":{"KOREA":"천 번 태어나서 만 번 부서질 죄악이로다.","JPN":"千回生まれ​直した上で万死に値する​罪悪である。","ENG":"You shall meet ten thousand deaths for your sins.","TWN":"此乃千生萬死之罪。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"사, 사도시여! 드디어 강림하셨군요!","JPN":"し、使徒様！　ついに降臨なされたのですね！","ENG":"A-apostle! You have finally come!","TWN":"使、使徒大人！您終於降臨了！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_QM","text":{"KOREA":"......너는 나의 전령이 아니로군.","JPN":"……貴様は余の伝令ではないな。","ENG":"You are not my messenger.","TWN":"……妳不是我的啟示者。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_QM","text":{"KOREA":"그녀는 어디에 있느냐?","JPN":"彼女はどこにいる？","ENG":"Where is she?","TWN":"她在哪裡？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"류, 류드밀라는 더 이상 무리를 이끌 능력이 없다고 판단되어......","JPN":"リュ、リュドミラは、もはや集団を率いる力を持っていないと\\n判断いたしましたので……","ENG":"I-I determined Lyudmila was no longer capable of leading the team...","TWN":"我、我們判斷盧德米拉不再具有領導我們的能力，所以……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_QM","text":{"KOREA":"네가 그녀의 등을 찔렀구나. 버러지 같으니.","JPN":"貴様が彼女の背中を刺したのか。虫けらめ。","ENG":"And thus you have planted your treacherous blade in her back. You worm.","TWN":"妳就捅了她背後一刀，跟隻螻蟻一樣。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"죄, 죄송합니다......","JPN":"も、申しわけございません……","ENG":"I-I'm sorry...","TWN":"對、對不起……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_QM","text":{"KOREA":"너는 생각할 필요가 없다. 판단할 필요도 없다.","JPN":"貴様は考えずともよい。判断せずともよい。","ENG":"You are not in any position to determine such things. Your thoughts are rendered invalid.","TWN":"不需要妳來思考，也不需要妳來判斷。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_QM","text":{"KOREA":"모든 것은 왕께서 결정해 주실 것이다.","JPN":"すべては王が決めてくださる。","ENG":"The Queen shall decide everything.","TWN":"王會決定一切。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"그렇습니다! 그렇고 말고요!","JPN":"ごもっともです！　おっしゃるとおりですとも！","ENG":"Indeed! I'm right with you there!","TWN":"是！當然！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"그런데...... 왕께서는 언제 강림하실지......","JPN":"し、しかし……王はいつになったら降臨なさるのか……","ENG":"By the way... When will the Queen be coming?","TWN":"不過……王何時會降臨……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_QM","text":{"KOREA":"그분께서 오시기엔 아직 때가 이르다.","JPN":"あの方がお越しになるにはまだ時が満ちていない。","ENG":"The time is yet unripe for his coming.","TWN":"王的到來還為時尚早。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_QM","text":{"KOREA":"비록 약해졌다고 하나, 왕의 앞길을 막는 저 불경한 봉인이 아직 건재하지 않느냐.","JPN":"弱まったとはいえ、王の進まれる道を阻む不敬なる封印が\\n未だ健在ではないか。","ENG":"Though it grows weak, the blasphemous seal still stands in the way of his return.","TWN":"就算變弱了，但擋住王去路的封印依舊存在。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_QM","text":{"KOREA":"허나 사도인 나의 힘은 충분히 회복되었으니, 이제 왕의 뜻을 이룰 반석을 세울 것이다.","JPN":"だが、使徒である余の力は十分回復している。\\nこれより王のご意志を実現する礎を築くとしよう。","ENG":"But as I, his apostle, have now had my power sufficiently restored, I shall lay the rock upon which the Queen's will be done.","TWN":"但身為使徒，我的力量已經恢復，足以奠定王意的基石了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"하온데, 사도시여.","JPN":"恐れながら申し上げます、使徒よ。","ENG":"Excuse me, Apostle...","TWN":"可是，使徒大人。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"미숙한 저와 저희 아이들이, 아직 원본을 흡수하지 못해 불완전합니다.","JPN":"私と私が率いる子どもたちは、\\nまだオリジナルを吸収できず不完全な状態です。","ENG":"I fear my kids and I have yet to absorb the originals. We are incomplete.","TWN":"我和孩子們太沒用，還沒有吸收到本體，依舊不夠完全。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_QM","text":{"KOREA":"......의심하지 말아라. 하찮은 반쪽짜리 그림자야.","JPN":"……王を疑ってはならぬ。取るに足りぬ半分の影よ。","ENG":"Do not doubt our lord's covenant, ye petty half-Shadow.","TWN":"……不要懷疑，卑賤又半吊子的暗影。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_QM","text":{"KOREA":"왕께서 걸음 하실 때, 너희도 보다 높은 존재로 <color=#ffd34c>재조립</color>될 것이다.","JPN":"王がその歩みを進められる時、貴様たちもより高い存在として<color=#ffd34c>組み直される</color>こととなろう。","ENG":"Upon our Queen's return, you shall be <color=#ffd34c>reassembled</color>, exalted to become higher beings.","TWN":"王到來時，你們也會以更高位的存在<color=#ffd34c>重組</color>的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"감사합니다......! 감사합니다!","JPN":"ああ……！　ありがとうございます……！","ENG":"Thank you! Thank you so much!","TWN":"謝謝您……！謝謝您！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_QM","text":{"KOREA":"자, 덧없는 병정들이여.","JPN":"行け、儚い兵卒たちよ。","ENG":"Come now, soldiers of transient existence.","TWN":"來吧，無常的士兵們啊。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_QM","text":{"KOREA":"왕의 이름으로 명하노니, 저 불경한 자들을 산산이 부서트릴지어다.","JPN":"王の名のもとに命ずる。\\nあの不敬なる者どもを木っ端微塵に粉砕せよ。","ENG":"I command you in the name of our Queen. Decimate those blasphemous fools.","TWN":"我以王的名命令你們，去撕裂那些不敬之徒吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};